module custom_logic (
    input k,
    input l,
    input m,
    input n,
    output reg obf_control);

    always @(*) begin
        case ({k, l, m, n})
            4'b1101: obf_control = 0;
            4'b0010: obf_control = 1;
            4'b1011: obf_control = 1;
            4'b0100: obf_control = 0;
            4'b1110: obf_control = 1;
            4'b0111: obf_control = 0;
            4'b1001: obf_control = 1;
            4'b0001: obf_control = 0;
            4'b1111: obf_control = 1;
            4'b0110: obf_control = 0;
            default: obf_control = 0;
        endcase
    end
endmodule
